sys_security_acl.script:
if(current.isNewRecord()) {
	answer = true;
} else {
	var taskerCommonScripts = new TaskerCommonScriptingMethods();
	try {
		var processTaskTemplateTableName = "x_153465_discovert_route_tasks";
		var taskTableName = "x_153465_discovert_route_task_instance";
		var taskingAuthorityTableName = "x_153465_discovert_discover_office_hierarchy";
		var sysId = current.sys_id;

		// prepare the query that will find out if this OU has a TA defined
		var ouTaQuery = [{"includeintaskingauthority": "true"}]; 
		// get the tasking authority table record that corresponds to the given ou sysId
		var taskingRecord = taskerCommonScripts.queryRelatedShort(taskingAuthorityTableName, ouTaQuery, function(record) {
			return record;
		}, true);
		// if we got a tasking authority record from the table, then we use it! If not, we print a warning in system logs
		if(taskingRecord[0]) {
			// with the tasking record found, get the sys_id of the tasking record
			var taskingRecordSysId = taskingRecord[0].sys_id;
			// active checker callback function, this function is used to check if a given record is active
			// will be used later in the script
			var hasActive = false;
			var isActive = function(record2) {
				if(record2.getValue("active") == true || record2.getValue("u_active") == true) {
					hasActive = true;
					return true;
				} else return false;
			};
			// loop through the process template tasks to find any active process template tasks that reference this ou in the "tasking authority" field 
			taskerCommonScripts.queryRelatedShort(processTaskTemplateTableName, [{"tasking_authority":taskingRecordSysId}], isActive, true);
			var taskQuery = [
				{"primary_assignee":sysId}, 
				{"primary_office":sysId},
				{"tasking_authority":current.sys_id}
			];
			// loop through all tasks to find if the current ou is referenced in any active task's tasking authority, primary office or assignee fields
			taskerCommonScripts.queryRelatedOrShort(taskTableName, null, taskQuery, isActive, true);
			// if any of the tasks or process template tasks are still active that reference this ou, then we do not allow modification of TA flag
			if(hasActive) {
				answer = false;
			} else {
				answer = true;
			}
		} else {
			taskerCommonScripts.commonMessage("[OU Hierarchy ACL]",  "Tasking authority table record for "+ current.office_abbreviation + " not found", gs.warn);
			answer = false;
		}

	} catch(e) {
		taskerCommonScripts.checkException("ACL", gs.error, e);
		answer = false;
	}
}
